  %arrayidx2 = getelementptr inbounds i32, ptr %out, i64 2
  store i32 %add.x, ptr %arrayidx2, align 4

  %arrayidx3 = getelementptr inbounds i32, ptr %out, i64 3
  store i32 %add.y, ptr %arrayidx3, align 4

  ret void
}

