381     if (!UseMask.empty()) {
382       const Value *Base = V;
383       while (auto *II = dyn_cast<InsertElementInst>(Base)) {
384         if (isa<T>(II->getOperand(1)))
385           continue;
386         Base = II->getOperand(0);
387         std::optional<unsigned> Idx = getInsertIndex(II);
388         if (!Idx)
