347 /// Prepares a use bitset for the given mask either for the first argument or
348 /// for the second.
349 static SmallBitVector buildUseMask(int VF, ArrayRef<int> Mask,
350                                    UseMask MaskArg) {
351   SmallBitVector UseMask(VF, true);
352   for (auto P : enumerate(Mask)) {
353     if (P.value() == UndefMaskElem) {
354       if (MaskArg == UseMask::UndefsAsMask)
355         UseMask.reset(P.index());
356       continue;
357     }
358     if (MaskArg == UseMask::FirstArg && P.value() < VF)
359       UseMask.reset(P.value());
360     else if (MaskArg == UseMask::SecondArg && P.value() >= VF)
361       UseMask.reset(P.value() - VF);
362   }
363   return UseMask;
364 }
